questionvariables.text:
/* Geometry logic */
k : rand([1, 2, 3]);
base_diff : 2 * k;
h : 4 * k;
slant : 5 * k;
b : rand_with_step(4, 10, 1);
a : b + (2 * base_diff);
/* 3. Pre-calculate values for the worked solution */
diff_single : (a - b) / 2;
h_sq : slant^2 - diff_single^2;
sum_ab : a + b;

/* Answer */
ta1 : (1/2) * (a + b) * h;
